#include <stdio.h>
#include <stdlib.h>
#define MOD 1234567891

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int A, B, N;
        scanf("%d %d %d", &A, &B, &N);
        long long sum = 0;
        for (int i = 1; i <= A; i++) {
            for (int j = 1; j <= B; j++) {
                if (i + j <= N) {
                    long long temp = 1;
                    for (int k = 1; k <= i; k++) {
                        temp = (temp * (k * k)) % MOD;
                    }
                    for (int k = 1; k <= j; k++) {
                        temp = (temp * (6 * k)) % MOD;
                    }
                    sum = (sum + temp) % MOD;
                }
            }
        }
        printf("%lld\n", sum);
    }
    return 0;
}

